import React, { useEffect, useState } from 'react';
import { login, leiloesService } from '../../services/api';
import AuctionCard from '../auctionCard/AuctionCard';

export default function AuctionMain() {
  const [leiloes, setLeiloes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [erro, setErro] = useState(null);

  useEffect(() => {
    async function carregarDados() {
      try {
        setLoading(true);
        
        // 1. Garante que estamos autenticados (Idealmente isso ficaria num Contexto de Auth global)
        const tokenAtual = localStorage.getItem('@Leiloes:token');
        if (!tokenAtual) {
          await login();
        }

        // 2. Busca os dados
        const response = await leiloesService.listarTodos();
        setLeiloes(response.data);

        // Exemplo de como usar com filtros:
        // const responseRJ = await leiloesService.listarPorLocalidade('RIO DE JANEIRO', 'RJ');
        
      } catch (err) {
        setErro('Falha ao carregar os leilões. Verifique o console.');
        console.error(err);
      } finally {
        setLoading(false);
      }
    }

    carregarDados();
  }, []);

  if (loading) return <p>Carregando leilões...</p>;
  if (erro) return <p>{erro}</p>;

  return (
    <div>
      <h2>Lista de Leilões</h2>
      <ul>
        {leiloes
            .filter((leilao) => leilao.tipo) // O filtro só deixa passar quem tem 'tipo' preenchido
            .map((leilao) => (
            <li key={leilao.id}>
                <AuctionCard 
                title={leilao.tipo} 
                description={leilao.cidade} 
                imageUrl={leilao.imagem} 
                />
            </li>
            ))}
        </ul>
    </div>
  );
}
